import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface Task {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
  progress: number;
  dependencies: string[];
}

interface GanttData {
  tasks: Task[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const ganttData = response.data as GanttData;
  const metaData = response.meta as MetaData;

  const { tasks } = ganttData;
  const themeColor = metaData.primaryColor;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: themeColor }}>
            Project Tasks
          </Typography>

          <Stack spacing={1.5}>
            {tasks.slice(0, 5).map((task) => (
              <Box key={task.id}>
                <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
                  <Typography variant="body2" sx={{ color: '#1F2937', fontWeight: 500 }}>
                    {task.name}
                  </Typography>
                  <Typography variant="caption" sx={{ color: themeColor }}>
                    {task.progress}%
                  </Typography>
                </Stack>
                <LinearProgress
                  variant="determinate"
                  value={task.progress}
                  sx={{
                    height: 8,
                    borderRadius: 4,
                    bgcolor: '#E0E0E0',
                    '& .MuiLinearProgress-bar': {
                      bgcolor: themeColor,
                      borderRadius: 4,
                    }
                  }}
                />
              </Box>
            ))}
          </Stack>

          <BarChart
            height={140}
            series={[
              {
                data: tasks.map(task => task.progress),
                color: metaData.accentColor,
              },
            ]}
            xAxis={[
              {
                data: tasks.map(task => task.name),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
